INSERT INTO auth.users (
INSERT INTO auth.identities (
INSERT INTO public.memos (user_id, title, content, tags)
VALUES
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'Vimの基本操作と設定方針', E'最近はNeovimをLuaで設定することに凝っている。\ninit.luaにLSPやTreesitterの設定を書くのは楽しいが、やりすぎると起動が遅くなるのが難点だ。\nMasonを使ってサーバーを管理しつつ、キーバインドはできるだけデフォルトの挙動を壊さないように工夫している。\n特にjkでのエスケープは手放せない。', ARRAY['Vim', 'Neovim', 'エディタ']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'レイトレーシングの数学的基礎', E'球体との交差判定には2次方程式の解の公式を利用する。\nベクトル演算が基本となるため、内積や外積の理解は必須だ。\nRay Tracing in One Weekendを読み進めているが、法線ベクトルを使ったライティングの実装で少し手こずった。\n反射光の計算にはランバート反射モデルを採用して、よりリアルな質感を追求したい。', ARRAY['グラフィックス', '数学', 'C++']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'Next.jsとSupabaseの連携', E'フロントエンドはNext.jsのApp Routerを採用し、サーバーサイドの処理を簡略化するためにSupabaseをバックエンドとして選定した。\nRow Level Securityの設定をしっかり行わないとセキュリティホールになるので注意が必要だ。\nJotaiを使った状態管理は直感的で、今回のエディタ開発にも非常にマッチしている。', ARRAY['React', 'Nextjs', 'データベース']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '三島由紀夫「金閣寺」の考察', E'美への執着と破滅がテーマとなっているこの作品は、文体が非常に緻密で美しい。\n主人公の吃音というコンプレックスが、金閣という絶対的な美に対してどのように作用していくのかを分析中。\n阿部公房の「砂の女」と対比させながら、実存主義的な視点で読み解くと非常に興味深い発見がある。', ARRAY['文学', '読書']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'ドイツ語の格変化と前置詞', E'ドイツ語には4つの格があり、前置詞によって支配される格が決まるのが非常に厄介だ。\n特に、場所の移動を表す場合は4格、静止している場合は3格という「2格支配の前置詞」の使い分けが難しい。\n大学の試験に向けて、不規則動詞の過去分詞形と一緒に毎日少しずつ暗記を進めている。', ARRAY['ドイツ語', '語学']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'N体シミュレーションの実装', E'C++を用いて重力相互作用による質点の運動を計算するプログラムを作成した。\nオイラー法では誤差が大きいため、ルンゲ＝クッタ法を導入して精度を向上させている。\n可視化にはOpenGLか、あるいはもっとシンプルにSFMLを使うか検討中。\n数万個の粒子をリアルタイムで動かすには空間分割法の導入が必要だ。', ARRAY['物理', 'プログラミング', 'C++']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'TypeScriptの型安全性について', E'ユニオン型やジェネリクスを駆使することで、実行時のエラーを劇的に減らすことができる。\n特にAPIのレスポンスに対してはZodを使ってスキーマバリデーションを行うのがモダンなやり方だ。\nPrismaの生成する型定義も非常に優秀で、データベース操作時の安心感が他のORMとは全く違う。', ARRAY['TypeScript', 'プログラミング']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '江戸川乱歩「押絵と旅する男」', E'この短編の幻想的な雰囲気は唯一無二だ。\n現実と虚構が混ざり合う境界線の描写が素晴らしく、乱歩特有の耽美的な世界観に引き込まれる。\nレンズを通した覗きから始まる物語の構成は、後のミステリー作品にも多大な影響を与えていると思う。\n視覚的なトリックが文字だけでこれほど表現できるのは驚きだ。', ARRAY['文学', 'ミステリー']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '線形代数における固有値の重要性', E'行列の固有値と固有ベクトルは、データの次元圧縮や物理学における振動解析など、多方面で応用されている。\n固有方程式を解く過程で現れる行列式の計算は、行列の大きさが3x3を超えると手計算では非常に困難になる。\n数値計算アルゴリズムとしてのべき乗法の仕組みについて、自主ゼミで発表する予定。', ARRAY['数学', '大学']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'Tailwind CSSの設計パターン', E'Tailwindは非常に便利だが、クラス名が長くなりがちなのが欠点だ。\nそこで、コンポーネント化を徹底し、共通のスタイルはshadcn/uiのように管理するのが効率的だと思う。\nカスタムカラーの定義をtailwind.config.tsに集約させることで、プロジェクト全体の色調を簡単に変更できる。', ARRAY['CSS', 'フロントエンド']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '朝のルーティンと集中力の維持', E'最近は朝食に冷凍ブルーベリーとヨーグルトを食べるようにしている。\n抗酸化作用のおかげか、午前中の集中力が以前より持続するようになった気がする。\nプログラミングは脳のエネルギー消費が激しいので、適切な栄養補給は欠かせない。\n作業の合間にはポモドーロ・テクニックを取り入れて休憩を挟んでいる。', ARRAY['健康', '生活']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '微積分学における極限の定義', E'イプシロン・デルタ論法による極限の定義は、直感的な理解を超えた厳密さを数学に与えている。\n最初は戸惑ったが、論理の組み立て方を理解すると、微分の定義がいかに巧妙に作られているかが分かる。\nテイラー展開を用いた関数の近似計算についても、プログラミングでの数値計算と結びつけて学習中。', ARRAY['数学', '大学']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'ブロックエディタのデータ構造', E'従来のテキストベースのエディタではなく、ブロック単位でデータを管理するエディタを設計している。\n各ブロックをJSON形式で保持することで、画像やコードブロックの埋め込みが容易になる。\nドラッグ＆ドロップによる並べ替え機能も実装したいが、状態管理が非常に複雑になりそうな予感がしている。', ARRAY['開発', 'React']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '江戸川乱歩のパノラマ島奇談', E'人工的な楽園を作り上げるという狂気的な美学に圧倒される。\n乱歩の作品の中でもスケールが大きく、描写が非常に色彩豊かだ。\n推理小説という枠を超えた、人間の欲望と狂気を描いた文学作品として評価されるべきだと思う。\n鏡やレンズといったガジェットの使い方が相変わらず巧みで面白い。', ARRAY['文学', 'ミステリー']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'ReactのServer Componentsの利点', E'Client Componentsとの使い分けを理解することで、バンドルサイズを劇的に削減できる。\nデータの取得はできるだけサーバーサイドで行い、インタラクティブな部分だけをクライアント側に任せるのがNext.js 13以降の王道だ。\n最初は戸惑ったが、この設計思想に慣れると開発効率が非常に高い。', ARRAY['React', 'Nextjs']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '離散数学とグラフ理論', E'最短経路問題やネットワークフローなど、グラフ理論はアルゴリズムの宝庫だ。\nダイクストラ法やベルマンフォード法の計算量について勉強している。\n競技プログラミングでもよく使われる知識なので、しっかり身につけておきたい。\n木構造の走査アルゴリズムも、ファイルシステムの設計に応用できる。', ARRAY['数学', '情報科学']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'ドイツの文化と歴史への関心', E'友人がドイツに留学しているので、現地の文化についてよく話を聞く。\nバウハウスのようなデザイン運動や、クラシック音楽の歴史には非常に興味がある。\nいつかドイツを訪れて、歴史的な建築物を自分の目で見てみたい。\nそのためにも、もっと流暢に会話ができるように語学学習を継続する必要がある。', ARRAY['ドイツ語', '歴史']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'フルスタック開発の難しさと楽しさ', E'データベースからUIまで一人で作り上げるのは大変だが、全体の構造を完全に把握できるのが最大の魅力だ。\nSupabaseのおかげでインフラ周りの構築コストが下がったため、よりプロダクトのロジックに集中できるようになった。\nフロントとバックをTypeScriptで統一できるのも、現代の開発の特権だ。', ARRAY['プログラミング', '開発']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '計算機システムとアセンブリ言語', E'高レイヤーの言語ばかり使っていると忘れがちだが、結局はCPUが命令を実行している。\nx86アセンブリを少し学ぶことで、メモリのスタックやヒープがどのように管理されているかの理解が深まった。\nレジスタの役割やシステムコールの仕組みを知ることは、パフォーマンス最適化の際にも役立つはずだ。', ARRAY['情報科学', '低レイヤー']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '三島由紀夫「沈める滝」の印象', E'ダム建設という無機質な近代化の象徴と、ドロドロとした人間関係の対比が印象的な作品だ。\n三島の作品に共通する「人工的な美」の追求がここでも見られる。\n自然という不確かなものを、人間の手で支配しようとする意志の強さを感じる。\n文体は冷徹だが、その奥にある情熱が読者に強く訴えかけてくる。', ARRAY['文学', '読書']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'ZustandとJotaiの比較検討', E'どちらも素晴らしいライブラリだが、今回のようなアトミックな状態管理にはJotaiが適していると感じた。\nZustandは1つの大きなストアを作るのに向いているが、Jotaiは個別の状態を細かく定義できるため、エディタのような複雑な依存関係がある場合には非常に扱いやすい。\n開発体験も非常に良い。', ARRAY['React', 'ライブラリ']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '物理エンジンの衝突検知アルゴリズム', E'AABB（軸平行境界ボックス）を使った大まかな判定から、より詳細な衝突地点の計算へと移るフェーズが面白い。\n摩擦や反発係数の計算を物理法則に基づいて実装することで、シミュレーションがぐっとリアルになる。\n剛体の回転運動まで考慮すると計算量が跳ね上がるので、四元数の理解が不可欠になる。', ARRAY['物理', 'プログラミング', 'C++']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '安部公房「他人の顔」について', E'仮面を被ることで自己のアイデンティティがどのように変化するかというテーマは、現代のSNS社会にも通じるものがある。\n安部公房の文体は非常に論理的で、まるで科学論文を読んでいるかのような冷徹さがあるが、それがかえって読者の想像力を刺激する。\n失われた顔を探す旅は、自己を見失った現代人の象徴だ。', ARRAY['文学', '読書']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'Rust言語への挑戦と期待', E'メモリ安全性を言語レベルで保証するRustに非常に興味がある。\n所有権や借用の概念は最初は難しいが、C++で発生しがちなメモリリークやセグフォをコンパイル時に防げるのは画期的だ。\n将来的には、今作っているレイトレーサーをRustで書き直して、どれくらいパフォーマンスが変わるか実験したい。', ARRAY['Rust', 'プログラミング']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'ハッカソンのチーム開発における交流', E'技術スタックを共有するだけでなく、お互いの得意分野を活かして1つのプロダクトを作り上げる過程は刺激的だ。\n今回はリーダーとして参加するが、メンバーの意見をうまく調整しながら、期限内に最高の成果物を出せるように努めたい。\n技術的な課題を議論することで、自分自身の知識も整理されていく。', ARRAY['ハッカソン', 'チーム開発']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'マークダウンパーサーの自作', E'正規表現を使ってテキストをHTMLに変換するシンプルなパーサーを書いてみた。\n見出し、強調、リストといった基本機能を実装するのはそれほど難しくないが、ネストした構造の処理になると途端に複雑になる。\n既存のライブラリがいかに高度なことをしているか痛感したが、自作することで仕組みがよく分かった。', ARRAY['開発', 'TypeScript']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'ドイツ語の試験に向けた勉強計画', E'試験まであと1ヶ月なので、単語の総復習と長文読解の練習に力を入れている。\nドイツ語のニュースサイトを毎日読んで、実際の語彙がどのように使われているかを確認するようにした。\nリスニング対策として、ポッドキャストを移動中に聞いている。\n文法だけでなく、文化背景を知ることも理解を助ける鍵だ。', ARRAY['ドイツ語', '大学']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '阿部公房「砂の女」の極限状態', E'砂という流動的なものに閉じ込められた男が、次第にその環境に適応していく過程が恐ろしくもあり、美しくもある。\n自由とは何か、定住とは何かという根源的な問いを突きつけてくる傑作だ。\n日常の裏側に潜む非日常を描く阿部公房の手法は、読者を不安にさせるが、それこそが文学の力だと再認識した。', ARRAY['文学', '読書']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'WSL2とUbuntuの開発環境構築', E'Windows上でLinuxが動くWSL2は、Web開発において非常に強力な武器になる。\nDockerとの親和性も高く、本番環境に近い状態で開発を進められるのが良い。\nNeovimの設定もWSL上のUbuntuで行っているが、クリップボードの共有など細かい設定を詰めることで、Macと遜色ない環境になった。', ARRAY['WSL', 'Linux', 'Vim']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '2Dキャンバスでの描画最適化', E'何千ものオブジェクトを描画する際、全ての描画命令を愚直に実行するとフレームレートが低下する。\nレイヤー分けを行ったり、画面外のオブジェクトを描画しない「カリング」を実装したりすることでパフォーマンスを向上させている。\nブラウザのレンダリングパイプラインを意識したコードを書くことが大切だ。', ARRAY['グラフィックス', 'フロントエンド', 'JavaScript']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'NeovimのLuaプラグイン開発', E'既存のプラグインを使うだけでなく、自分で必要な機能を作るのも勉強になる。\nLuaはシンプルで書きやすい言語なので、Vim scriptよりも直感的にAPIを叩ける。\nまずは簡単な文字数カウントのプラグインから自作してみる予定だ。', ARRAY['Vim', 'Neovim', '開発']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'C++でのポインタとメモリ管理', E'スマートポインタを活用することで、生のポインタによるメモリリークを防ぐことができる。\nstd::unique_ptrとstd::shared_ptrの使い分けは、オブジェクトの所有権を明確にする上で非常に重要だ。\n特にゲームエンジン開発においては、パフォーマンスと安全性のバランスが求められる。', ARRAY['C++', 'プログラミング']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '江戸川乱歩「陰獣」の二重構造', E'本格推理の枠組みを借りながら、読者を翻弄するメタフィクション的な仕掛けが秀逸。\n寒川と大江春泥の関係性が、そのまま作家と読者の関係を反映しているようにも読める。\nグロテスクな描写の中に潜む、計算し尽くされたプロットの美しさについて考察を深めたい。', ARRAY['文学', 'ミステリー', '読書']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '三島由紀夫の「仮面の告白」', E'自己分析の極致とも言える作品。\n内面的な衝動をこれほどまでに客観的かつ論理的に描写する筆力に圧倒される。\n社会的な規範と個人的な欲望の間の葛藤は、普遍的なテーマとして現代にも通じる。\n表現の正確さが、逆に感情の激しさを際立たせている。', ARRAY['文学', '読書']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'ドイツ語の接続法第2式', E'非現実の願望や仮定を表す接続法第2式は、会話でもよく使われる重要な文法だ。\nwürdeを使った迂言形と、動詞自体を変化させる形があり、最初は混乱した。\nもし～だったら、という表現の幅が広がるので、しっかり使いこなせるように練習している。', ARRAY['ドイツ語', '語学']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'SupabaseのEdge Functions', E'バックエンドのロジックをDenoで書いてエッジで実行できる機能。\nAPIのレスポンスを高速化したり、外部サービスとの連携をサーバーサイドで行ったりするのに便利だ。\nTypeScriptでそのまま書けるので、コンテキストスイッチが発生しないのが素晴らしい。', ARRAY['Supabase', 'TypeScript', 'バックエンド']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'Prismaのマイグレーション', E'スキーマファイルを変更した後のデータベースへの反映が非常にスムーズ。\nSQLを直接書くよりも、モデルの定義を見ればテーブル構造が一目でわかるのが利点だ。\n初期開発の段階ではスキーマの変更が頻繁に起こるため、この恩恵は計り知れない。', ARRAY['データベース', 'Prisma', 'ORM']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'Reactのカスタムフック', E'コンポーネント間でロジックを再利用するための強力なパターン。\nウィンドウサイズを監視するフックや、LocalStorageと同期するフックを作ってみた。\nUIとロジックを分離することで、コードの可読性が格段に上がり、テストも書きやすくなる。', ARRAY['React', 'フロントエンド']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '動的計画法とアルゴリズム', E'大きな問題を小さな部分問題に分割し、その結果をメモ化して再利用する手法。\nナップサック問題などで威力を発揮するが、状態の定義と遷移の漸化式を立てるのが難しい。\n紙に図を書いて状態の遷移を可視化するのが、理解への一番の近道だと感じた。', ARRAY['アルゴリズム', '情報科学']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '線形代数とコンピュータグラフィックス', E'3D空間でのオブジェクトの移動、回転、拡大縮小はすべて行列の掛け算で表現される。\n同次座標系を導入することで、平行移動も行列演算に含められるのは美しい。\n数学の理論が、画面上のピクセルの色として視覚化されるプロセスは非常に面白い。', ARRAY['数学', 'グラフィックス']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'ブルーベリーと眼精疲労', E'画面を見続ける時間が長いので、目に良いとされるアントシアニンを意識して摂取している。\n冷凍のものが保存もきき、ヨーグルトに混ぜて食べるのにちょうど良い。\n定期的に遠くを見るなど、物理的な目の休憩も合わせて行うようにしている。', ARRAY['健康', '生活']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'ハッカソンのプレゼン準備', E'技術的な優位性だけでなく、なぜそのプロダクトを作ったのかという背景のストーリーが重要だ。\nデモのシナリオを作り込み、想定されるトラブルへの対策も練っておく必要がある。\nスライドはシンプルに保ち、実際の動くアプリを見せることに時間を割きたい。', ARRAY['ハッカソン', 'チーム開発']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'WSL2のネットワーク設定', E'WSL側からホストのWindowsのポートにアクセスしたり、その逆を行ったりする際の設定。\nlocalhostでの解決がうまくいかない場合があるため、IPアドレスの指定などネットワークの基礎知識が必要になる。\n開発用サーバーの公開設定など、少しつまづきやすいポイントだ。', ARRAY['WSL', 'ネットワーク']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'TypeScriptのUtility Types', E'PickやOmit、Partialなどを使いこなすと、型定義の重複を大きく減らせる。\nデータベースのモデル型から、APIのレスポンス用の型を生成する際などに非常に役立つ。\n型のパズルを解いているような感覚があり、適切に型がついたときの爽快感は格別だ。', ARRAY['TypeScript', 'プログラミング']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '物理エンジンにおける剛体の力学', E'質点ではなく大きさを持った物体の運動をシミュレーションするためには、慣性モーメントの考慮が必要だ。\n力の加わる位置によってトルクが発生し、回転運動が引き起こされる。\nこの計算を正確に行うことで、ブロックが崩れるような自然なアニメーションが作れる。', ARRAY['物理', 'C++', 'プログラミング']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'Zustandのミドルウェア', E'persistミドルウェアを使うと、状態を自動的にLocalStorageに保存・復元してくれる。\nユーザーの設定や一時的な入力データを保持するのに非常に便利だ。\n複雑な設定なしに数行追加するだけで機能拡張できるのがZustandの強みだと思う。', ARRAY['React', 'ライブラリ']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'Tailwind CSSのカスタムプラグイン', E'プロジェクト固有の複雑なユーティリティクラスが必要な場合、プラグインとして切り出して定義できる。\nデザインシステムを厳密に適用したい場合に、標準のクラスだけでは足りない部分を補える。\nJavaScriptでスタイルを定義できる柔軟性が良い。', ARRAY['CSS', 'フロントエンド']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'Next.jsのキャッシュ制御', E'fetch関数のオプションで、データのキャッシュの有効期限や再検証のタイミングを細かく制御できる。\n静的サイトのパフォーマンスと、動的サイトの情報の鮮度を両立させるための要となる機能だ。\nキャッシュのパージ戦略は、アプリケーションの要件に合わせて慎重に設計する必要がある。', ARRAY['Nextjs', 'React']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', '離散数学の論理演算', E'命題論理や述語論理は、プログラミングにおける条件分岐の基礎となる。\nド・モルガンの法則などを意識してコードを書くことで、複雑なif文をシンプルにリファクタリングできる。\n真理値表を書いて論理の漏れや重複がないか確認する癖をつけておきたい。', ARRAY['数学', '情報科学']),
  ('df49e059-8950-47f2-8689-8a6f0711f1dd', 'レイトレーシングでの屈折の計算', E'ガラスや水などの透明な物体を表現するためには、スネルの法則に基づいて光線の屈折方向を計算する。\n全反射の条件も考慮する必要があり、反射と屈折を組み合わせることでガラス玉のような美しいレンダリング結果が得られる。\n物理法則の数式がそのままコードに落ちていく感覚が楽しい。', ARRAY['グラフィックス', '物理', '数学']);